def factorial(n):
    fact = 1
    for i in range(2, n + 1):
        fact = fact * i
    return fact


def permutation(n):
    p = 1
    for i in range(2, n + 1):
        p = p * i
    return p


def count_distinct_subarrays(n):
    mod = 998244353
    sum = 0
    for i in range(1, n + 1):
        sum = (sum + factorial(i - 1) * permutation(n - i)) % mod
    return sum


n = int(input())
print(count_distinct_subarrays(n))



